import{_ as e,o as a,c as d,a2 as r}from"./chunks/framework.BZO4qERu.js";const b=JSON.parse('{"title":"騎砍2 | 賺錢密技：從窮鬼到卡拉迪亞首富之路","description":"","frontmatter":{},"headers":[],"relativePath":"bannerlord/money-making.md","filePath":"bannerlord/money-making.md"}'),l={name:"bannerlord/money-making.md"};function n(i,t,o,h,s,c){return a(),d("div",null,[...t[0]||(t[0]=[r(`<h1 id="騎砍2-賺錢密技-從窮鬼到卡拉迪亞首富之路" tabindex="-1">騎砍2 | 賺錢密技：從窮鬼到卡拉迪亞首富之路 <a class="header-anchor" href="#騎砍2-賺錢密技-從窮鬼到卡拉迪亞首富之路" aria-label="Permalink to &quot;騎砍2 | 賺錢密技：從窮鬼到卡拉迪亞首富之路&quot;">​</a></h1><hr><h2 id="前言-第納爾不會從天上掉下來-除非你開作弊" tabindex="-1">前言：第納爾不會從天上掉下來（除非你開作弊） <a class="header-anchor" href="#前言-第納爾不會從天上掉下來-除非你開作弊" aria-label="Permalink to &quot;前言：第納爾不會從天上掉下來（除非你開作弊）&quot;">​</a></h2><p>在騎砍2裡，<strong>錢就是一切</strong>。</p><p>有錢 = 養得起兵 = 打得贏仗 = 搶更多錢 = 養更多兵。</p><p>沒錢 = 兵跑光 = 被山賊欺負 = 回到新手村。</p><p>這篇把遊戲裡所有合法賺錢方式都整理給你，從新手到後期都有。</p><hr><h2 id="一、四條賺錢路線總覽" tabindex="-1">一、四條賺錢路線總覽 <a class="header-anchor" href="#一、四條賺錢路線總覽" aria-label="Permalink to &quot;一、四條賺錢路線總覽&quot;">​</a></h2><table tabindex="0"><thead><tr><th>路線</th><th style="text-align:center;">啟動門檻</th><th style="text-align:center;">穩定收入</th><th>適合階段</th></tr></thead><tbody><tr><td>競技場</td><td style="text-align:center;">0 金</td><td style="text-align:center;">500-1500 / 場</td><td>遊戲開局</td></tr><tr><td>跑商</td><td style="text-align:center;">3000 金</td><td style="text-align:center;">2000-5000 / 趟</td><td>前期到中期</td></tr><tr><td>工廠</td><td style="text-align:center;">8000 金</td><td style="text-align:center;">200-500 / 天</td><td>中期被動收入</td></tr><tr><td>鍛造</td><td style="text-align:center;">5000 金+鍛造100</td><td style="text-align:center;">5000-30000 / 天</td><td>後期暴富</td></tr></tbody></table><hr><h2 id="二、第一階段-窮人求生-身家-0-5000-金" tabindex="-1">二、第一階段：窮人求生（身家 0-5000 金） <a class="header-anchor" href="#二、第一階段-窮人求生-身家-0-5000-金" aria-label="Permalink to &quot;二、第一階段：窮人求生（身家 0-5000 金）&quot;">​</a></h2><h3 id="🏟️-方法-1-競技場刷錢" tabindex="-1">🏟️ 方法 1：競技場刷錢 <a class="header-anchor" href="#🏟️-方法-1-競技場刷錢" aria-label="Permalink to &quot;🏟️ 方法 1：競技場刷錢&quot;">​</a></h3><p>每個城市都有競技場，去報名練習賽：</p><ul><li>贏一場獎金 250-500 金</li><li>掉的裝備是你的</li><li><strong>不會死人</strong>，輸了就昏倒而已</li><li>帝國競技場裝備統一，最容易贏</li></ul><blockquote><p>💡 泡在競技場練到能穩定打贏，這就是你的第一筆穩定收入。</p></blockquote><h3 id="📦-方法-2-村莊跑腿任務" tabindex="-1">📦 方法 2：村莊跑腿任務 <a class="header-anchor" href="#📦-方法-2-村莊跑腿任務" aria-label="Permalink to &quot;📦 方法 2：村莊跑腿任務&quot;">​</a></h3><p>去找各村莊的村長接任務：</p><table tabindex="0"><thead><tr><th>任務</th><th>報酬</th><th style="text-align:center;">麻煩程度</th></tr></thead><tbody><tr><td>送貨</td><td>300-800</td><td style="text-align:center;">簡單</td></tr><tr><td>找失蹤村民</td><td>200-500</td><td style="text-align:center;">簡單</td></tr><tr><td>趕牛</td><td>400-1000</td><td style="text-align:center;">煩人但安全</td></tr><tr><td>打土匪</td><td>1000-3000</td><td style="text-align:center;">需要能打</td></tr></tbody></table><blockquote><p>送貨任務最穩，前期就是一直送貨、存錢。</p></blockquote><h3 id="🛡️-方法-3-賣俘虜" tabindex="-1">🛡️ 方法 3：賣俘虜 <a class="header-anchor" href="#🛡️-方法-3-賣俘虜" aria-label="Permalink to &quot;🛡️ 方法 3：賣俘虜&quot;">​</a></h3><p>打山賊/土匪之後：</p><ul><li>俘虜敵方士兵</li><li>去城市酒館找<strong>贖金經紀人</strong></li><li>一個普通俘虜能賣 30-80 金</li><li>高級俘虜能賣到幾百</li></ul><hr><h2 id="三、第二階段-中產階級-身家-5000-50000-金" tabindex="-1">三、第二階段：中產階級（身家 5000-50000 金） <a class="header-anchor" href="#三、第二階段-中產階級-身家-5000-50000-金" aria-label="Permalink to &quot;三、第二階段：中產階級（身家 5000-50000 金）&quot;">​</a></h2><h3 id="🏭-方法-4-開工廠-被動收入" tabindex="-1">🏭 方法 4：開工廠（被動收入！） <a class="header-anchor" href="#🏭-方法-4-開工廠-被動收入" aria-label="Permalink to &quot;🏭 方法 4：開工廠（被動收入！）&quot;">​</a></h3><p>去城市裡找工匠 NPC，選擇買工廠。</p><table tabindex="0"><thead><tr><th>工廠類型</th><th>推薦城市</th><th style="text-align:center;">日收入</th><th style="text-align:center;">啟動成本</th></tr></thead><tbody><tr><td>釀酒廠</td><td>南帝國 <strong>達努斯蒂卡 Danustica</strong></td><td style="text-align:center;">200-400</td><td style="text-align:center;">8000</td></tr><tr><td>釀酒廠</td><td>北帝國 <strong>阿爾戈隆 Argoron</strong></td><td style="text-align:center;">200-400</td><td style="text-align:center;">8000</td></tr><tr><td>天鵝絨廠</td><td>北帝國 <strong>阿爾戈隆 Argoron</strong></td><td style="text-align:center;">200-400</td><td style="text-align:center;">15000</td></tr><tr><td>鐵匠舖</td><td>斯特吉亞 <strong>奧莫爾 Omor</strong></td><td style="text-align:center;">100-250</td><td style="text-align:center;">6000</td></tr></tbody></table><blockquote><p>💡 <strong>第一座工廠建議：</strong> 南帝國達努斯蒂卡釀酒廠。周圍村莊 Menzura、Qasira 全是穀物產地，原料便宜到哭，穩定日入 200-400 金，約 20-40 天回本。</p></blockquote><h3 id="🐪-方法-5-跑商" tabindex="-1">🐪 方法 5：跑商 <a class="header-anchor" href="#🐪-方法-5-跑商" aria-label="Permalink to &quot;🐪 方法 5：跑商&quot;">​</a></h3><p>遊戲中每個城鎮的物價是<strong>浮動的</strong>，取決於該城鎮周圍村莊生產什麼。</p><p>滑鼠移過去看到<strong>綠色</strong> = 便宜，<strong>紅色</strong> = 貴。</p><table tabindex="0"><thead><tr><th>路線</th><th>起點</th><th>終點</th><th>貨物</th><th style="text-align:center;">單趟利潤</th></tr></thead><tbody><tr><td>🥇 穀物線</td><td>南帝國村莊</td><td>北帝國城鎮</td><td>穀物</td><td style="text-align:center;">3000-5000</td></tr><tr><td>🥈 硬木線</td><td>巴坦尼亞村莊</td><td>阿塞萊城鎮</td><td>硬木</td><td style="text-align:center;">2000-4000</td></tr><tr><td>🥉 牲畜線</td><td>庫塞特村莊</td><td>帝國城鎮</td><td>羊/牛/馬</td><td style="text-align:center;">2000-3000</td></tr></tbody></table><blockquote><p>💡 買 3-5 頭騾子增加負重，但不要買太多——移動速度 = 安全。</p></blockquote><h3 id="🏛️-方法-6-當雇傭兵" tabindex="-1">🏛️ 方法 6：當雇傭兵 <a class="header-anchor" href="#🏛️-方法-6-當雇傭兵" aria-label="Permalink to &quot;🏛️ 方法 6：當雇傭兵&quot;">​</a></h3><p>加入一個正在打仗的國家當雇傭兵：</p><ul><li>每日薪水：依部隊規模，後期約 200-500 金/天</li><li>打仗的分成：參戰可以分戰利品</li><li>打仗本身就是賺錢（戰利品、俘虜、裝備）</li></ul><hr><h2 id="四、第三階段-財富自由-身家-50000-金" tabindex="-1">四、第三階段：財富自由（身家 50000+ 金） <a class="header-anchor" href="#四、第三階段-財富自由-身家-50000-金" aria-label="Permalink to &quot;四、第三階段：財富自由（身家 50000+ 金）&quot;">​</a></h2><h3 id="🔨-方法-7-鍛造系統-—-遊戲最暴利的賺錢方式-💎" tabindex="-1">🔨 方法 7：鍛造系統 — 遊戲最暴利的賺錢方式 💎 <a class="header-anchor" href="#🔨-方法-7-鍛造系統-—-遊戲最暴利的賺錢方式-💎" aria-label="Permalink to &quot;🔨 方法 7：鍛造系統 — 遊戲最暴利的賺錢方式 💎&quot;">​</a></h3><p>這遊戲的鍛造系統，說好聽點叫「自由打造武器」，說難聽點叫「合法印鈔機」。</p><p><strong>怎麼搞：</strong></p><ol><li>買便宜的鐵礦/粗鐵</li><li>熔掉變成材料</li><li>鍛造成<strong>雙手劍</strong></li><li>一把頂級雙手劍可以賣到 <strong>8000-30000 金</strong></li></ol><p><strong>最佳賺錢配方：</strong></p><table tabindex="0"><thead><tr><th>部位</th><th>推薦配件</th><th style="text-align:center;">等級</th></tr></thead><tbody><tr><td>刀刃</td><td>帝國刀刃</td><td style="text-align:center;">T5</td></tr><tr><td>護手</td><td>裝飾護手</td><td style="text-align:center;">T4</td></tr><tr><td>握柄</td><td>皮革長握柄</td><td style="text-align:center;">T4</td></tr><tr><td>配重</td><td>鋼配重塊</td><td style="text-align:center;">T3</td></tr></tbody></table><blockquote><p>材料成本約 500 金 → 成品價值 8000-15000 金 → <strong>利潤率 1600-3000%</strong></p></blockquote><p><strong>練鍛造等級捷徑：</strong></p><ul><li>熔煉武器給的經驗遠大於鍛造</li><li>所有打仗撿到的武器**不要賣！**拿去熔煉</li><li>找有鍛造技能的同伴幫忙</li></ul><h3 id="⚔️-方法-8-打仗賺錢" tabindex="-1">⚔️ 方法 8：打仗賺錢 <a class="header-anchor" href="#⚔️-方法-8-打仗賺錢" aria-label="Permalink to &quot;⚔️ 方法 8：打仗賺錢&quot;">​</a></h3><p>當你有能力打大仗之後：</p><ul><li>打贏一場大戰，光是賣戰利品就能賺幾萬</li><li>俘虜高級領主可以勒索贖金（幾萬到十幾萬）</li><li>打下城市/城堡獲得稅收</li></ul><h3 id="🏰-方法-9-擁有封地" tabindex="-1">🏰 方法 9：擁有封地 <a class="header-anchor" href="#🏰-方法-9-擁有封地" aria-label="Permalink to &quot;🏰 方法 9：擁有封地&quot;">​</a></h3><p>當你獲得城市/城堡後：</p><ul><li>城市稅收：每日 500-2000+ 金</li><li>城堡稅收：每日 200-800 金</li><li>領地越多，收入越高</li></ul><hr><h2 id="五、賺錢優先級懶人包" tabindex="-1">五、賺錢優先級懶人包 <a class="header-anchor" href="#五、賺錢優先級懶人包" aria-label="Permalink to &quot;五、賺錢優先級懶人包&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>前期：競技場 → 跑腿任務 → 打山賊賣俘虜</span></span>
<span class="line"><span>     ↓</span></span>
<span class="line"><span>中期：開工廠 → 跑商 → 當雇傭兵</span></span>
<span class="line"><span>     ↓</span></span>
<span class="line"><span>後期：鍛造印鈔 → 打仗 → 攻城 → 收稅 → 躺著數錢</span></span></code></pre></div><hr><h2 id="🕳️-常見燒錢陷阱" tabindex="-1">🕳️ 常見燒錢陷阱 <a class="header-anchor" href="#🕳️-常見燒錢陷阱" aria-label="Permalink to &quot;🕳️ 常見燒錢陷阱&quot;">​</a></h2><table tabindex="0"><thead><tr><th>陷阱</th><th>後果</th><th>解法</th></tr></thead><tbody><tr><td>兵太多養不起</td><td>破產、士兵叛逃</td><td>在有穩定收入前，部隊不要招滿上限</td></tr><tr><td>急著升級所有兵</td><td>錢瞬間花光</td><td>先升前排步兵，弓兵慢慢來</td></tr><tr><td>買最好的裝備</td><td>全身頂裝要幾十萬</td><td>中期買中階裝備就夠了</td></tr><tr><td>把錢花光</td><td>突發事件無法應對</td><td>永遠留足以養兵 7 天的錢</td></tr></tbody></table><hr><h2 id="結語-先投資-後享受" tabindex="-1">結語：先投資，後享受 <a class="header-anchor" href="#結語-先投資-後享受" aria-label="Permalink to &quot;結語：先投資，後享受&quot;">​</a></h2><p>騎砍2的經濟邏輯很簡單：</p><p><strong>前期辛苦存錢 → 中期投資（工廠）→ 後期錢自己進來</strong></p><p>不要急著當大爺花錢，先把錢拿去生錢。等你每天躺著就有幾千塊收入，那才是真正的自由。</p><hr><h2 id="📖-相關攻略" tabindex="-1">📖 相關攻略 <a class="header-anchor" href="#📖-相關攻略" aria-label="Permalink to &quot;📖 相關攻略&quot;">​</a></h2><ul><li>還不知道怎麼招兵？→ <a href="./troop-tier-list.html">騎砍2 | 兵種大亂鬥</a></li><li>賺夠了想建國？→ <a href="./kingdom-building.html">騎砍2 | 自立為王</a></li><li>遊戲本體玩膩了？→ <a href="./mod-recommendations.html">騎砍2 | 2026 必裝 MOD 推薦</a></li></ul><hr><p><em>Blades Game 游刃攻略 — 遊刃有餘的遊戲攻略。全部原創內容，未經授權禁止轉載。</em></p><hr><h2 id="更新紀錄" tabindex="-1">更新紀錄 <a class="header-anchor" href="#更新紀錄" aria-label="Permalink to &quot;更新紀錄&quot;">​</a></h2><ul><li><strong>2026-06-11</strong>：文章建立。依據遊戲 v1.4.x 正式版撰寫。</li></ul>`,73)])])}const g=e(l,[["render",n]]);export{b as __pageData,g as default};
